Here is a sketch that does this:

```cpp
#include <LiquidCrystal_I2C.h>
#include <DHT.h>

#define DHT_PIN 2
#define DHTTYPE DHT11

DHT dht(DHT_PIN, DHTTYPE);
LiquidCrystal_I2C lcd(0x27, 16, 2);

void setup() {
  Serial.begin(9600);
  lcd.init();
  lcd.backlight();
  dht.begin();

  lcd.setCursor(0, 0);
  lcd.print("DHT IS READY!");
  delay(3000);
  lcd.clear();

  lcd.setCursor(0, 0);
  lcd.print("INITIALIZING...");
  delay(2000);
  lcd.clear();

  lcd.print("READING....");
  delay(2000);
  lcd.clear();
}

void loop() {
  delay(2000);
  float h = dht.readHumidity();
  float t = dht.readTemperature();

  if (isnan(h) || isnan(t)) {
    lcd.clear();
    lcd.setCursor(0, 0);
    lcd.print("Sensor Error");
  } else {
    char line1[17];
    char line2[17];
    snprintf(line1, sizeof(line1), "HUMIDITY: %4.1f%%", h);
    snprintf(line2, sizeof(line2), "TEMP: %4.1fC", t);

    lcd.setCursor(0, 0);
    lcd.print(line1);
    lcd.setCursor(0, 1);
    lcd.print(line2);

    delay(10000);
  }
}
```

Notes:
- `dht.readHumidity()`/`readTemperature()` return `NAN` on a failed read, so both are checked with `isnan()`.
- The 2 s delay at the top of `loop()` respects the DHT11's minimum ~1 s sampling interval with margin.
- Values are written into fixed-width buffers with `snprintf` so a shorter new reading fully overwrites a longer old one, instead of leaving stray digits on the LCD.

